UPDATE t_p28211681_photo_secure_web.legal_documents
SET content = REPLACE(
  content,
  '5.5. Рекуррентные списания: при выборе автопродления Заказчик дает явное согласие на периодическое списание платежей в размере и с периодичностью, указанными на Сайте. Заказчик может в любой момент отключить автопродление в ЛК; Исполнитель направляет предварительное уведомление о предстоящем списании на e‑mail за [3] дня до него. По каждому списанию формируется чек НПД.</p>',
  '5.5. Рекуррентные (автоматически повторяющиеся) списания. При подключении функции автопродления подписки Заказчик даёт явное согласие на автоматическое периодическое списание денежных средств с привязанного платёжного инструмента на следующих условиях:</p>
<p>5.5.1. <b>Период и стоимость.</b> Размер периодического платежа равен стоимости выбранного Тарифа за указанный период (1 месяц или иной период, выбранный при оформлении). Актуальные цены всегда размещены на Сайте в разделе «Тарифы».</p>
<p>5.5.2. <b>Дата списания.</b> Первое списание производится в момент оформления подписки. Каждое последующее списание производится автоматически в тот же день месяца, что и первое списание (например, если первое списание прошло 15-го числа, следующее — 15-го числа следующего расчётного периода). Если в расчётном месяце нет соответствующего числа, списание производится в последний день такого месяца.</p>
<p>5.5.3. <b>Уведомление.</b> Исполнитель направляет Заказчику предварительное уведомление о предстоящем списании на адрес электронной почты, указанный при регистрации, не менее чем за 3 (три) календарных дня до даты списания. Заказчик несёт ответственность за актуальность указанного адреса электронной почты.</p>
<p>5.5.4. <b>Отмена автопродления.</b> Заказчик вправе в любой момент отключить автопродление в Личном кабинете (раздел «Тарифы» → «Управление подпиской») или направив запрос на support@foto-mix.ru. При отключении автопродления доступ к платным функциям сохраняется до окончания оплаченного периода, после чего Тариф переключается на бесплатный «Старт».</p>
<p>5.5.5. <b>Возврат средств.</b> При отмене подписки в течение 14 (четырнадцати) дней с момента первого списания и при отсутствии существенного использования Сервиса Заказчик вправе запросить возврат средств, направив обращение на support@foto-mix.ru. Возврат осуществляется тем же способом, которым была произведена оплата, в течение 10 рабочих дней. По истечении 14 дней денежные средства за текущий оплаченный период не возвращаются.</p>
<p>5.5.6. <b>Изменение стоимости.</b> Об изменении стоимости Тарифа при автопродлении Исполнитель уведомляет Заказчика не менее чем за 30 (тридцать) календарных дней до вступления изменения в силу. Если Заказчик не отменил автопродление до даты изменения, считается, что он согласен с новой стоимостью.</p>
<p>5.5.7. <b>История согласий.</b> Исполнитель сохраняет запись о согласии Заказчика на автоматические списания (дата, сумма, тариф, версия оферты). Продолжение использования Сервиса после получения уведомления об изменении условий считается согласием с такими изменениями.</p>
<p>5.5.8. <b>Платёжные данные.</b> Привязка платёжного инструмента осуществляется через платёжную систему Robokassa. Исполнитель не хранит данные банковских карт Заказчика. При недостаточности средств на счёте Заказчика в дату списания Исполнитель вправе повторить попытку в течение 3 дней, после чего при отсутствии успешного списания подписка переводится в неактивный статус.</p>'
)
WHERE slug = 'offer';
